class Solution {
    TreeNode* build(vector<int>& a, int l, int r) {
        if (l > r) return nullptr;
        int m = l + (r - l) / 2;
        auto* nd = new TreeNode(a[m]);
        nd->left = build(a, l, m - 1);
        nd->right = build(a, m + 1, r);
        return nd;
    }
public:
    TreeNode* sortedArrayToBST(vector<int>& nums) {
        return build(nums, 0, nums.size() - 1);
    }
};
